#!/usr/bin/env node
import "dotenv/config";
import { Command } from "commander";
import { runEmbed } from "./commands/embed";
import { runQuery } from "./commands/query";
import { runSummarize } from "./commands/summarize";
import { promptLlm } from "./utils/llm";

const program = new Command();

program
  .name("diffdoc")
  .description("Translate repository code shifts into plain-English business context")
  .version("0.1.0");

program
  .command("summarize")
  .description("Summarize repository code into a portable JSON manifest")
  .option("--path <path>", "repository or code path to scan", ".")
  .option("--out <path>", "manifest output path under DIFFDOC_BASE_DIR", "manifest.json")
  .option("--mode <mode>", "summarization mode: all or delta", "all")
  .action(async (options: { path: string; out: string; mode: string }) => {
    try {
      await runSummarize({ path: options.path, out: options.out, mode: options.mode as "all" | "delta" });
    } catch (error) {
      console.error(error instanceof Error ? error.message : error);
      process.exit(1);
    }
  });

program
  .command("prompt")
  .description("Send a plain prompt to the configured LLM")
  .argument("<message...>", "prompt text to send")
  .action(async (messageParts: string[]) => {
    try {
      const response = await promptLlm(messageParts.join(" "));
      console.log(response);
    } catch (error) {
      console.error(error instanceof Error ? error.message : error);
      process.exit(1);
    }
  });

program
  .command("query")
  .description("Search the local Vectra index with a natural-language question")
  .argument("<message...>", "question or search text")
  .option("--top <count>", "number of matches to return", "5")
  .option("--code", "include code snapshots in results", false)
  .action(async (messageParts: string[], options: { top: string; code: boolean }) => {
    try {
      await runQuery(messageParts.join(" "), options);
    } catch (error) {
      console.error(error instanceof Error ? error.message : error);
      process.exit(1);
    }
  });

program
  .command("embed")
  .description("Embed manifest summaries into a local Vectra index")
  .option("--manifest <path>", "manifest input path under DIFFDOC_BASE_DIR", "manifest.json")
  .action(async (options: { manifest: string }) => {
    try {
      await runEmbed({ manifest: options.manifest });
    } catch (error) {
      console.error(error instanceof Error ? error.message : error);
      process.exit(1);
    }
  });

program.parseAsync(process.argv).catch((error: unknown) => {
  console.error(error instanceof Error ? error.message : error);
  process.exit(1);
});

