import "dotenv/config";
import OpenAI from "openai";

type Provider = "local" | "cloud";

function getProvider(): Provider {
  return process.env.AI_PROVIDER === "cloud" ? "cloud" : "local";
}

function createClient(): { client: OpenAI; model: string } {
  const provider = getProvider();
  const apiKey = provider === "cloud" ? process.env.OPENAI_API_KEY : process.env.OPENAI_API_KEY || "local-key";
  const baseURL = provider === "cloud" ? process.env.CLOUD_LLM_ENDPOINT : process.env.LOCAL_LLM_ENDPOINT;
  const model = provider === "cloud" ? process.env.CLOUD_CHAT_MODEL : process.env.LOCAL_CHAT_MODEL;

  if (!baseURL) {
    throw new Error(`Missing ${provider === "cloud" ? "CLOUD_LLM_ENDPOINT" : "LOCAL_LLM_ENDPOINT"} configuration.`);
  }
  if (!model) {
    throw new Error(`Missing ${provider === "cloud" ? "CLOUD_CHAT_MODEL" : "LOCAL_CHAT_MODEL"} configuration.`);
  }
  if (provider === "cloud" && !apiKey) {
    throw new Error("Missing OPENAI_API_KEY for cloud provider.");
  }

  return {
    client: new OpenAI({ apiKey, baseURL }),
    model
  };
}

export async function generateFunctionalSummary(fileName: string, codeContent: string): Promise<string> {
  const { client, model } = createClient();
  const response = await client.chat.completions.create({
    model,
    temperature: 0.2,
    messages: [
      {
        role: "system",
        content: "Explain what this code does for non-technical stakeholders. Focus on business behavior, user impact, rules, data movement, and visible outcomes. Use plain English, avoid jargon, and provide zero conversational preamble."
      },
      {
        role: "user",
        content: `File: ${fileName}\n\nCode:\n${codeContent}`
      }
    ]
  });

  return response.choices[0]?.message?.content?.trim() || "No business behavior summary was returned.";
}

export async function promptLlm(prompt: string): Promise<string> {
  const { client, model } = createClient();
  const response = await client.chat.completions.create({
    model,
    temperature: 0.2,
    messages: [
      {
        role: "user",
        content: prompt
      }
    ]
  });

  return response.choices[0]?.message?.content?.trim() || "No response was returned.";
}

export function getEmbeddingConfig(): { provider: Provider; apiKey: string; model: string; baseURL?: string } {
  const provider = getProvider();
  const apiKey = provider === "cloud" ? process.env.OPENAI_API_KEY || "" : process.env.OPENAI_API_KEY || "local-key";
  const model = provider === "cloud" ? process.env.CLOUD_EMBED_MODEL : process.env.LOCAL_EMBED_MODEL;
  const baseURL = provider === "local" ? process.env.LOCAL_EMBED_ENDPOINT : process.env.CLOUD_LLM_ENDPOINT;

  if (!model) {
    throw new Error(`Missing ${provider === "cloud" ? "CLOUD_EMBED_MODEL" : "LOCAL_EMBED_MODEL"} configuration.`);
  }
  if (provider === "cloud" && !apiKey) {
    throw new Error("Missing OPENAI_API_KEY for cloud provider.");
  }

  return { provider, apiKey, model, baseURL };
}

export async function generateEmbeddings(texts: string[]): Promise<number[][]> {
  const embeddingConfig = getEmbeddingConfig();
  const baseURL = embeddingConfig.baseURL?.replace(/\/embeddings\/?$/, "");
  const client = new OpenAI({ apiKey: embeddingConfig.apiKey, baseURL });
  const response = await client.embeddings.create({
    model: embeddingConfig.model,
    input: texts
  });

  return response.data.map((item) => item.embedding);
}

