import path from "node:path";

export function getDiffdocBaseDir(): string {
  return path.resolve(process.cwd(), process.env.DIFFDOC_BASE_DIR || "./.diffdoc");
}

export function resolveDiffdocArtifactPath(filePath: string): string {
  if (path.isAbsolute(filePath)) {
    return filePath;
  }

  return path.resolve(getDiffdocBaseDir(), filePath);
}
